int raw_feature_get_data(size_t offset, size_t length, float *out_ptr) {
  memcpy(out_ptr, features + offset, length * sizeof(float));
  return 0;
}

void print_inference_result(ei_impulse_result_t result) {

    // Print how long it took to perform inference
    ei_printf("Timing: DSP %d ms, inference %d ms, anomaly %d ms\r\n",
            result.timing.dsp,
            result.timing.classification,
            result.timing.anomaly);

    // Print the prediction results (object detection)
#if EI_CLASSIFIER_OBJECT_DETECTION == 1
    ei_printf("Object detection bounding boxes:\r\n");
    for (uint32_t i = 0; i < result.bounding_boxes_count; i++) {
        ei_impulse_result_bounding_box_t bb = result.bounding_boxes[i];
        if (bb.value == 0) {
            continue;
        }
        ei_printf("  %s (%f) [ x: %u, y: %u, width: %u, height: %u ]\r\n",
                bb.label,
                bb.value,
                bb.x,
                bb.y,
                bb.width,
                bb.height);
    }

    // Print the prediction results (classification)
#else
    ei_printf("Predictions:\r\n");
    for (uint16_t i = 0; i < EI_CLASSIFIER_LABEL_COUNT; i++) {
        ei_printf("  %s: ", ei_classifier_inferencing_categories[i]);
        ei_printf("%.5f\r\n", result.classification[i].value);
    }
#endif

    // Print anomaly result (if it exists)
#if EI_CLASSIFIER_HAS_ANOMALY == 1
    ei_printf("Anomaly prediction: %.3f\r\n", result.anomaly);
#endif

}

extern "C" int app_main()
{
    // Initial heap check
    // check_heap_integrity("app_main start");
    
    // setup_led();
    ei_sleep(100);

    ei_impulse_result_t result = { nullptr };
    // Initialize the result structure

    ei_printf("Edge Impulse standalone inferencing (Espressif ESP32)\n");
    
    // Print memory information
    // check_heap_integrity("before main loop");

    if (sizeof(features) / sizeof(float) != EI_CLASSIFIER_DSP_INPUT_FRAME_SIZE)
    {
        ei_printf("The size of your 'features' array is not correct. Expected %d items, but had %u\n",
                EI_CLASSIFIER_DSP_INPUT_FRAME_SIZE, sizeof(features) / sizeof(float));
        return 1;
    }

    int iteration = 0;

    int64_t start_time = esp_timer_get_time();

    while (true)
    {
        iteration++;
        ESP_LOGI(TAG, "=== Starting inference iteration %d ===", iteration);
        
        // Check heap before each iteration
        // check_heap_integrity("iteration start");
        
        // blink LED
        gpio_set_level(LED_PIN, 1);

        // the features are stored into flash, and we don't want to load everything into RAM
        signal_t features_signal;
        features_signal.total_length = sizeof(features) / sizeof(features[0]);
        features_signal.get_data = &raw_feature_get_data;

        ESP_LOGI(TAG, "Running classifier...");
        
        // invoke the impulse
        EI_IMPULSE_ERROR res = run_classifier(&features_signal, &result, false /* debug */);

        ESP_LOGI(TAG, "Classifier finished with result: %d", res);  
        
        
        // Check heap after inference
        // check_heap_integrity("after inference");
        
        // if (res != EI_IMPULSE_OK) {
        //     ei_printf("ERR: Failed to run classifier (%d)\n", res);
        //     check_heap_integrity("after classifier error");
        //     return res;
        // }

        // print_inference_result(result);

        // gpio_set_level(LED_PIN, 0);
        
        // // Check heap before sleep
        // check_heap_integrity("before sleep");
        
        ESP_LOGI(TAG, "=== Completed inference iteration %d ===", iteration);

        // Print the time taken for the inference
        int64_t end_time = esp_timer_get_time();
        int64_t elapsed_time = end_time - start_time;
        elapsed_time /= 1000; // Convert microseconds to milliseconds
        ESP_LOGI(TAG, "Time taken for inference: %lld ms", elapsed_time);
        ESP_LOGI(TAG, "Start time = %lld, End time = %lld", start_time, end_time);
        start_time = end_time; // Reset start time for the next iteration


        ei_sleep(1000); // Increased sleep to allow heap monitoring
    }
}

